import json
import re
import os

# Load existing temp questions if exists
all_new_questions = []
if os.path.exists('temp_new_questions.json'):
    with open('temp_new_questions.json', 'r', encoding='utf-8') as f:
        all_new_questions = json.load(f)
    print(f"Loaded {len(all_new_questions)} from temp file")

def add_qs(cat, title, diff, content, answer, tags):
    all_new_questions.append({
        'id': f'{cat}-{len([q for q in all_new_questions if q["category"] == cat])+1}',
        'title': title,
        'category': cat,
        'difficulty': diff,
        'content': content[:150],
        'answer': answer,
        'sourceType': 'builtin',
        'source': f'{cat}面试题',
        'tags': tags,
    })

# Count current needs
with open('index.html', 'r', encoding='utf-8') as f:
    html = f.read()
pattern = r'const BUILTIN_QUESTIONS=\[([\s\S]*?)\];'
match = re.search(pattern, html)
qs_str = match.group(1) if match else ""
cur = {}
for m in re.finditer(r"category:'(\w[\w-]*)'", qs_str):
    c = m.group(1)
    cur[c] = cur.get(c, 0) + 1

print("Current counts:")
for c in sorted(cur.keys()):
    print(f"  {c}: {cur[c]} (need {max(0, 201-cur[c])} more)")

